#include <stdio.h>
#include <string.h>

int main() {
	int i, l;
	static char n[11];
	static char *s[] = {
		"O-|-OOOO",
		"O-|O-OOO",
		"O-|OO-OO",
		"O-|OOO-O",
		"O-|OOOO-",
		"-O|-OOOO",
		"-O|O-OOO",
		"-O|OO-OO",
		"-O|OOO-O",
		"-O|OOOO-"
	};
	scanf("%s", n);
	l = strlen(n);
	for (i = l - 1; i >= 0; i--)
		printf("%s\n", s[n[i] - '0']);
	return 0;
}

